import{c as r,Q as i,j as s,g as e,n as o}from"./chunks/framework.hhGiamYR.js";const f=JSON.parse('{"title":"第16章","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/scholarship/najemy-power/16-ch16.md","filePath":"research/machiavelli/scholarship/najemy-power/16-ch16.md"}'),t={name:"research/machiavelli/scholarship/najemy-power/16-ch16.md"};function n(l,a,c,p,d,h){return i(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"第16章",tabindex:"-1"},[o("第16章 "),e("a",{class:"header-anchor",href:"#第16章","aria-label":'Permalink to "第16章"'},"​")],-1),e("p",null,"第一章 文艺复兴时期的书信 39",-1),e("p",null,"文献记录。正如彼特拉克在《致友人书》的开篇献辞中回忆的，他 对这些信感到十分气愤和厌恶，以致他立刻写下他那著名的对西 塞罗的抱怨信，因为他“通晓”(familiaritate) 西塞罗思想“就像他 是生活在我的时代的一位友人”。①他问西塞罗，写哲学论著的哲 人怎么能背叛他自己的内心宁静和斯多葛思想的理念，自甘堕落 到政治的野心与腐化中去呢?②相比之下，塞涅卡的《致卢齐利乌 斯的信》[26](也被称作《道德书简》[ Epistulae Morales])更多具 有道德哲学论文和沉思的性质。尽管信是写给一个有名有姓的朋 友，甚至此人还会时不时给他一些意见，但这些信只不过是采用了 书信的形式，使得塞涅卡可以对一个并不在场的他者提出劝诫与 教导。由于彼特拉克批评了西塞罗的政治书信，我们本应期待他 选择塞涅卡为典范的。然而，彼特拉克声称他在《致友人书》中更 多追随的是西塞罗而非塞涅卡，同时声称那些写给阿提库斯的信 “挑动”和“惹怒”了他。彼特拉克如此解释他对其书信写作艺术 的古代典范的反应和评价，反映出他发觉自己所复兴甚或开创的 体裁尚不存在明晰确切的权威性典范。正是由于文艺复兴时期的 书信写作有着多种典范和传统的印记，因此相比于其他类型的人 文主义写作，它成为创作更自由和试验幅度更大的一片领域。 试验的某些可能性与指向性体现在《致友人书》的结构之中， 也体现在第一封导言性的信中。自然，彼特拉克在他的信集中收 入了一些他尚未有任何收集成书打算之前的信，不过，正如我们将 要看到的，他重新创作和修订了其中的很多封信。他还增添了一",-1),e("p",null,"①Francesco Petrarca, Le familiari, vol.1,edVittorio Rossi,Florence:Sansoni,1933, pp.3-14;the passage referred to is on pp.12-13.The English translation of this letter is by Aldo S.Bernardo in Francesco Petrarca, Rerum familiarium libriI-VII, Albany, N.Y.:State University of New York Press,1975,pp.3-14. ②Le familiari 24.3,in vol.4,ed.V.Rossi and U.Bosco,Florence:Sansoni,1942, pp.225-227.",-1),e("p",null,"些写给同时代人的、如今被视作“虚构写作”的未必会送出的信， 做成早已写好的样子，然后在书信集中精心安排了它们的位置，从 而表达出有关其人生某一阶段的特定想法或者印象。记叙他攀登 旺图山的信或许是这些特意创作的信中最有名的，彼特拉克把它 安排在1336年，但是根据彼拉诺维奇的研究，它的创作时间不早 于1350年代早期或中期。彼特拉克努力掩盖这些信的写作时间 实际上晚于其标明时间多年，这就需要一切现代考据学的精湛技 艺将“真实的”(或者我们是否可以直接说“日期准确的”?)和“虚 构的”分开。①但是，在《致友人书》开篇的献辞(写给一位被他称 为苏格拉底的朋友的信)里，彼特拉克几乎承认了(也总是令人感 到疑惑)他整个书信集里的所有书信都介于事实与虚构的模糊状 态之中，至少也暗示了书信这一体裁本身就是如此。他在这封信 中告诉苏格拉底[27]他是怎么决定要将自己的书信集结成书以 及某种能够反映其内容特点的东西，这封信在此意义上成为文艺 复兴时期人文主义的书信写作学问的基础文本。因为它的许多主 题一直与文艺复兴时期的书信写作有关并将复现在马基雅维利与 韦托里的通信中。有必要仔细阅读它，并将其作为某种开场白。 彼特拉克在开头讲了一个关于书信集如何成形的故事。当他 在家里考虑搬家时，“被一大堆杂乱无章的书信和一摞摞形状各 异的纸稿团团围住”,他“开始随意地翻看这些无序地摞起来的纸 稿”并且“惊讶地发现总体上它们相当多样和混乱。我几乎没法 辨认出其中的某些，并不是因为它们的形状而是因为我自己的理",-1),e("p",null,"①Giuseppe Billanovich,Petrarca letterato, Rome:Edizioni di storia e letteratura, 1947;也可参见贝尔纳多《致友人书》译本的导言，他在其中对彼拉诺维奇的主要 发现做了有益的概括，见前注21。另一种观点认为彼特拉克不可能公然欺骗读者 和完全创作书信，参见Hans Baron, Petrarch's Secretum:Its Making and Its Mean- ing,Cambridge,Mass.:The Medieval Academy of America,1985,esp.pp.185- 214,and,for Baron's reading of Familiari I.I,pp.7-15。",-1)])])}const u=r(t,[["render",n]]);export{f as __pageData,u as default};
